ps.pstext:
if !IsFeatureImplemented(FEAT_SME2) && !IsFeatureImplemented(FEAT_SVE2p1) then
    EndOfDecode(Decode_UNDEF);
end;
let n : integer = UInt(Rn);
let g : integer = UInt('1'::PNg);
let nreg : integer{} = 2;
let t : integer = UInt(Zt::'0');
let esize : integer{} = 64;
let offset : integer = SInt(imm4);

if !IsFeatureImplemented(FEAT_SME2) && !IsFeatureImplemented(FEAT_SVE2p1) then
    EndOfDecode(Decode_UNDEF);
end;
let n : integer = UInt(Rn);
let g : integer = UInt('1'::PNg);
let nreg : integer{} = 4;
let t : integer = UInt(Zt::'00');
let esize : integer{} = 64;
let offset : integer = SInt(imm4);

if IsFeatureImplemented(FEAT_SVE2p1) then CheckSVEEnabled(); else CheckStreamingSVEEnabled(); end;
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mbytes : integer{} = esize DIV 8;
var base : bits(64);
var addr : bits(64);
let pred : bits(PL) = P{}(g);
let mask : bits(PL * nreg) = CounterToPredicate{}(pred[15:0]);
var values : array [[4]] of bits(VL);
let contiguous : boolean = TRUE;
let nontemporal : boolean = TRUE;
let transfer : integer = t;
let tagchecked : boolean = n != 31;
let accdesc : AccessDescriptor = CreateAccDescSVE(MemOp_LOAD, nontemporal, contiguous,
                                                     tagchecked);

if !AnyActiveElement{PL*nreg}(mask, esize) then
    if n == 31 && ConstrainUnpredictableBool(Unpredictable_CHECKSPNONEACTIVE) then
        CheckSPAlignment();
    end;
else
    if n == 31 then CheckSPAlignment(); end;
end;

base = if n == 31 then SP{64}() else X{64}(n);
addr = AddressAdd(base, offset * nreg * elements * mbytes, accdesc);

for r = 0 to nreg-1 do
    for e = 0 to elements-1 do
        if ActivePredicateElement{PL*nreg}(mask, r * elements + e, esize) then
            values[[r]][e*:esize] = Mem{esize}(addr, accdesc);
        else
            values[[r]][e*:esize] = Zeros{esize};
        end;
        addr = AddressIncrement(addr, mbytes, accdesc);
    end;
end;

for r = 0 to nreg-1 do
    Z{VL}(transfer+r) = values[[r]];
end;
